// Also apply GOOGL mapping to GOOG (same company, different share class)
RESEARCHED.GOOG = RESEARCHED.GOOGL;

// ── INJECT INTO ADJUDICATION ──

const adjPath = latest(/__role_mapping_adjudication_v2_reviewed__/);
const adjContent = readFileSync(adjPath, "utf8");
const { headers: adjHeaders, rows: adjRows } = parseSimpleCsv(adjContent);

// Remove any existing rows for researched tickers, then add new ones
const researchedTickers = new Set(Object.keys(RESEARCHED));
const filteredRows = adjRows.filter((r) => !researchedTickers.has(r.ticker));

let nextId = 1;
const newRows = [];
for (const [ticker, mappings] of Object.entries(RESEARCHED)) {
  for (const m of mappings) {
    const exposure = scoreByLabel.get(m.label);
    if (!Number.isFinite(exposure)) {
      console.warn(`WARNING: Unknown label ${m.label} for ${ticker}, skipping`);
      continue;
    }
    newRows.push({
      adjudication_id: `ADJ-RESEARCH-${RUN_ID}-${ticker}-${String(nextId++).padStart(3, "0")}`,
      run_id: RUN_ID,
      mapping_review_id: "",
      signal_id: "",
      ticker,
      role_phrase_raw: m.note.split(".")[0],
      signal_type: "pct",
      signal_value: String(m.share),
      implied_share_pct: m.share.toFixed(2),
      normalized_role_bucket: m.label.split("-")[0],
      suggested_repo_label: m.label,
      suggested_repo_title: "",
      suggested_repo_score: String(exposure),
      mapping_confidence: m.conf,
      confidence_rationale: "Deep research: company-specific reasoning with 10-K + web evidence.",
      review_status: "approved",
      approved_repo_label: m.label,
      approved_share_pct: m.share.toFixed(2),
      reviewer: REVIEWER,
      reviewed_at: NOW_ISO,
      review_notes: m.note,
      citation_id: `CITEXT-RESEARCH-${RUN_ID}-${ticker}`,
      quote: m.note,
      created_at: NOW_ISO,
    });
  }
}

const allRows = [...filteredRows, ...newRows].sort((a, b) =>
  String(a.adjudication_id || "").localeCompare(String(b.adjudication_id || "")),
);

const outPath = path.join(INT_DIR, `${RUN_ID}__role_mapping_adjudication_v2_reviewed__${STAMP}.csv`);
writeFileSync(outPath, toCsv(allRows, adjHeaders), "utf8");

const approved = allRows.filter((r) => r.review_status === "approved").length;
const tickers = new Set(allRows.filter((r) => r.review_status === "approved").map((r) => r.ticker));
console.log(`Wrote: ${outPath}`);
console.log(`Total rows: ${allRows.length} | Approved: ${approved} | Tickers with approvals: ${tickers.size}`);
console.log(`Injected research for: ${Object.keys(RESEARCHED).join(", ")}`);
